// ============================================================
// PARSE SOURCE ARTICLE HTML
// Extract title, sections, and image URLs from source page
// ============================================================
const html = $input.first().json.body || $input.first().json.data || '';

// Extract title
const titleMatch = html.match(/<h1[^>]*>([^<]+)<\/h1>/i);
const articleTitle = titleMatch ? titleMatch[1].trim() : 'ציוד פיקוד ובקרה לתעשייה';

// Extract article body — look for main content area
const articleMatch = html.match(/<article[^>]*>([\s\S]*?)<\/article>/i) ||
                     html.match(/<main[^>]*>([\s\S]*?)<\/main>/i) ||
                     html.match(/<div[^>]*class[^>]*content[^>]*>([\s\S]*?)<\/div>/i);
const articleBody = articleMatch ? articleMatch[1] : html;

// Extract H2 sections
const sections = [];
const h2Regex = /<h2[^>]*(?:id="([^"]+)")?[^>]*>([^<]+)<\/h2>([\s\S]*?)(?=<h2|<\/article|$)/gi;
let match;
while ((match = h2Regex.exec(articleBody)) !== null) {
  const sectionId = match[1] || 'section-' + sections.length;
  const sectionTitle = match[2].trim();
  const sectionContent = match[3].trim();
  if (sectionTitle && sectionContent.length > 50) {
    sections.push({id: sectionId, title: sectionTitle, content: sectionContent});
  }
}

// Extract image URLs from source
const imgRegex = /<img[^>]+src="([^"]+mapril\.websmail\.net[^"]+)"/gi;
const articleImages = [];
let imgMatch;
while ((imgMatch = imgRegex.exec(html)) !== null) {
  if (!articleImages.includes(imgMatch[1])) {
    articleImages.push(imgMatch[1]);
  }
}

// Fallback images if none found
const fallbackImages = [
  'https://mapril.websmail.net/wp-content/uploads/2026/04/WhichIndustrialControlInstrumentsAreCommonToday.jpg',
  'https://mapril.websmail.net/wp-content/uploads/2026/04/HowtoChooseaSupplierforCommandandControlEquipment.jpg',
  'https://mapril.websmail.net/wp-content/uploads/2026/04/TestsandMetricsWhattoCheckBeforePurchasingControlandMeasurementEquipment.jpg',
  'https://mapril.websmail.net/wp-content/uploads/2026/04/CommonMistakesinSelectingControlEquipmentAndHowtoAvoidThem.jpg'
];

const finalImages = articleImages.length >= 3 ? articleImages : fallbackImages;

// Extract paragraphs for content analysis
const paragraphs = [];
const pRegex = /<p[^>]*>([\s\S]*?)<\/p>/gi;
while ((match = pRegex.exec(articleBody)) !== null) {
  const text = match[1].replace(/<[^>]+>/g, '').trim();
  if (text.length > 80) paragraphs.push(text);
}

console.log('Sections found:', sections.length);
console.log('Images found:', finalImages.length);
console.log('Paragraphs found:', paragraphs.length);

return [{
  json: {
    articleTitle,
    articleBody,
    sections,
    articleImages: finalImages,
    paragraphs,
    sourceUrl: 'https://mapril.websmail.net/industrial-control-and-command-equipment/',
    targetKeyword: 'ציוד פיקוד ובקרה',
    processedAt: new Date().toISOString()
  }
}];

// ============================================================
// PARSE AI RESPONSE & EXTRACT ARTICLE DATA
// ============================================================
const aiResponse = $input.first().json;
const sourceData = $('Parse Article Sections').first().json;

let articleData;
try {
  // Try to parse AI response as JSON
  const content = aiResponse.message?.content || aiResponse.choices?.[0]?.message?.content || JSON.stringify(aiResponse);
  articleData = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  // Fallback to source data structure
  console.log('AI response parse failed, using fallback:', e.message);
  articleData = {
    title: sourceData.articleTitle || 'ציוד פיקוד ובקרה לתעשייה: המדריך המקיף',
    intro: 'בחירת ציוד פיקוד ובקרה לתעשייה היא אחת ההחלטות הטכניות המשמעותיות ביותר בכל מערכת ייצור.',
    takeaways: [
      'ציוד פיקוד ובקרה מורכב משלוש שכבות: קליטת נתונים, עיבוד ושליטה, ותגובה והפעלה',
      'רכישה לפי מחיר בלבד ללא התאמה לתנאי הסביבה היא הטעות הנפוצה ביותר',
      'בחירת ספק מתאים כוללת תמיכה טכנית בעברית וניסיון מוכח',
      'בדיקת תאימות תקשורת לפני הרכישה חוסכת אינטגרציה בעייתית',
      'גלעוז אלקטרוניקה מעניקה ייעוץ מקצועי חינם לפני כל בחירת ציוד'
    ],
    sections: sourceData.sections.map((s, i) => ({
      id: s.id,
      heading: s.title,
      content: s.content
    })),
    faqItems: [
      {q: 'מה ההבדל בין PLC לבין PAC?', a: 'PLC מותאם לפעולות לוגיות מהירות. PAC מוסיף יכולות מחשוב ואינטגרציה רחבה עם IT ו-SCADA.'},
      {q: 'איזה פרוטוקולי תקשורת עדיף להשתמש בתעשייה הישראלית?', a: 'Modbus TCP, EtherNet/IP ו-Profinet הם הנפוצים ביותר. ל-IIoT: OPC UA ו-MQTT.'},
      {q: 'כמה זמן לוקח אספקת ציוד בקרה?', a: 'רכיבים במלאי: ימים בודדים. הזמנה מיוחדת: שבועיים עד 3 חודשים.'}
    ],
    closingParagraph: 'גלעוז אלקטרוניקה כאן כדי ללוות אתכם לכל אורך הדרך, מהאפיון הראשוני ועד הפעלה מלאה בשטח.'
  };
}

return [{
  json: {
    ...sourceData,
    articleData,
    parsedAt: new Date().toISOString()
  }
}];

// ============================================================
// GENERATE FULL HTML ARTICLE
// Full production HTML with all required elements per MyClaw prompt
// ============================================================

const data = $input.first().json;
const ad = data.articleData || {};
const images = data.articleImages || [];

// Brand constants
const BRAND = {
  primary: '#005696',
  accent: '#0E6BA8',
  dark: '#1F2D3D',
  text: '#334155',
  bg: '#ffffff',
  surface: '#f8fafc',
  border: '#e2e8f0',
  logo: 'https://d3m9l0v76dty0.cloudfront.net/system/logos/7002/original/f2a1fcfa083f4d83b3269684e5fe223e.png',
  contact: 'https://www.galoz.co.il/contact',
  whatsapp: 'https://wa.me/972522516009',
  phone: '079-5805040',
  email: 'sales@galoz.co.il',
  homepage: 'https://www.galoz.co.il/',
  phoneDisplay: '079-5805040'
};

// Title and sections
const title = ad.title || data.articleTitle || 'ציוד פיקוד ובקרה לתעשייה: המדריך המקיף';
const intro = ad.intro || 'בחירת ציוד פיקוד ובקרה לתעשייה היא אחת ההחלטות הטכניות המשמעותיות ביותר.';
const sections = ad.sections || data.sections || [];
const takeaways = ad.takeaways || [];
const faqItems = ad.faqItems || [];

// ---- SINGLE H1 ENFORCEMENT ----
// All sections use H2; only the title uses H1
let h1Count = 0;
function safeH2(tag) {
  if (tag === 'h1') {
    h1Count++;
    return h1Count === 1 ? 'h1' : 'h2';
  }
  return tag;
}

// ---- HELPER FUNCTIONS ----
function hoverBtn(bg, hoverBg) {
  return `onmouseover="this.style.background='${hoverBg}'" onmouseout="this.style.background='${bg}'`;
}

function sectionH2(id, text) {
  return `<h2 id="${id}" style="font-size:1.5rem;font-weight:700;color:${BRAND.dark};margin:48px 0 16px;border-bottom:2px solid ${BRAND.primary};padding-bottom:8px;">${text}</h2>`;
}

function tipBlock(text) {
  return `<div style="background:#eff6ff;border-right:4px solid #3b82f6;border-radius:8px;padding:16px 20px;margin:24px 0;"><p style="margin:0;font-size:0.9rem;color:#1e40af;font-weight:700;">💡 טיפ מקצועי</p><p style="margin:8px 0 0;font-size:0.9rem;color:${BRAND.text};line-height:1.6;">${text}</p></div>`;
}

function howtoBlock(title, steps) {
  const stepsHtml = steps.map(s => `<li>${s}</li>`).join('');
  return `<div style="background:#f0fdf4;border-right:4px solid #22c55e;border-radius:8px;padding:16px 20px;margin:24px 0;"><p style="margin:0;font-size:0.9rem;color:#166534;font-weight:700;">🔧 ${title}</p><ol style="margin:10px 0 0;padding-right:20px;font-size:0.9rem;color:${BRAND.text};line-height:1.8;">${stepsHtml}</ol></div>`;
}

function dynBlock(text) {
  return `<div style="background:#fefce8;border-right:4px solid #eab308;border-radius:8px;padding:16px 20px;margin:24px 0;"><p style="margin:0;font-size:0.9rem;color:#854d0e;font-weight:700;">💡 האם ידעתם?</p><p style="margin:8px 0 0;font-size:0.9rem;color:${BRAND.text};line-height:1.6;">${text}</p></div>`;
}

function sectionImg(src, alt) {
  if (!src) return '';
  return `<img src="${src}" alt="${alt}" style="width:100%;max-width:100%;height:auto;border-radius:10px;margin:1.5rem 0;display:block;" loading="lazy">`;
}

function bodyPara(text) {
  if (!text) return '';
  if (text.startsWith('<p')) return text;
  return `<p style="font-size:1rem;line-height:1.7;color:${BRAND.text};margin-bottom:1.2rem;">${text}</p>`;
}

// ---- TOC ----
const tocItems = sections.map(s =>
  `<li style="padding:6px 0;border-bottom:1px solid #f1f5f9;"><a href="#${s.id}" style="color:${BRAND.text};text-decoration:none;font-size:0.9rem;" onmouseover="this.style.color='${BRAND.primary}';this.style.textDecoration='underline'" onmouseout="this.style.color='${BRAND.text}';this.style.textDecoration='none'">${s.heading}</a></li>`
).join('');

const tocHtml = `
<details style="border:1px solid ${BRAND.border};border-radius:10px;margin-bottom:28px;overflow:hidden;">
<summary style="cursor:pointer;padding:14px 20px;font-weight:700;font-size:1rem;color:${BRAND.dark};list-style:none;display:flex;align-items:center;justify-content:space-between;background:${BRAND.surface};" onmouseover="this.style.background='#f1f5f9'" onmouseout="this.style.background='${BRAND.surface}'"><span>📋 תוכן עניינים</span><span style="font-size:1.1rem;color:${BRAND.accent};">＋</span></summary>
<nav style="padding:12px 20px 16px;"><ol style="margin:0;padding-right:20px;list-style:none;">${tocItems}<li style="padding:6px 0;"><a href="#section-faq" style="color:${BRAND.text};text-decoration:none;font-size:0.9rem;" onmouseover="this.style.color='${BRAND.primary}';this.style.textDecoration='underline'" onmouseout="this.style.color='${BRAND.text}';this.style.textDecoration='none'">שאלות נפוצות</a></li></ol></nav>
</details>`;

// ---- TAKEAWAYS ----
const takeawayItems = takeaways.map(t =>
  `<li style="padding:6px 0;color:${BRAND.text};font-size:0.95rem;display:flex;align-items:flex-start;gap:8px;"><span style="color:${BRAND.primary};font-weight:700;flex-shrink:0;">◆</span>${t}</li>`
).join('');

const takeawaysHtml = `<div style="background:${BRAND.surface};border-right:4px solid ${BRAND.accent};border-radius:8px;padding:20px 24px;margin-bottom:32px;"><h2 style="font-size:1.1rem;font-weight:700;color:${BRAND.dark};margin:0 0 12px;">בקצרה — מה תלמדו במאמר זה</h2><ul style="margin:0;padding:0;list-style:none;">${takeawayItems}</ul></div>`;

// ---- MID ARTICLE CTA ----
const midCTA = `<div style="background:linear-gradient(135deg,${BRAND.primary} 0%,#003f6e 100%);border-radius:12px;padding:28px 24px;margin:40px 0;text-align:center;"><p style="font-size:1.2rem;font-weight:700;color:#fff;margin:0 0 8px;">מחפשים פתרון שמתאים ליישום שלכם?</p><p style="font-size:0.95rem;color:rgba(255,255,255,0.9);margin:0 0 20px;line-height:1.6;">התאמה נכונה של בקר, חיישן, ממיר או רכיב תקשורת מקצרת זמני התקנה וחוסכת תקלות בשטח.</p><div style="display:flex;gap:12px;justify-content:center;flex-wrap:wrap;"><a href="${BRAND.contact}" style="display:inline-flex;align-items:center;gap:8px;background:#ffffff;color:${BRAND.primary};font-size:0.95rem;font-weight:700;padding:12px 28px;border-radius:8px;text-decoration:none;" onmouseover="this.style.background='#f0f7ff';this.style.boxShadow='0 4px 16px rgba(0,0,0,0.2)'" onmouseout="this.style.background='#ffffff';this.style.boxShadow='none'">📞 ליצירת קשר וייעוץ</a><a href="${BRAND.whatsapp}" target="_blank" rel="noopener" style="display:inline-flex;align-items:center;gap:8px;background:#25D366;color:#fff;font-size:0.95rem;font-weight:700;padding:12px 28px;border-radius:8px;text-decoration:none;" onmouseover="this.style.background='#1da851'" onmouseout="this.style.background='#25D366'">💬 WhatsApp</a></div><p style="margin:16px 0 0;font-size:0.85rem;color:rgba(255,255,255,0.75);">📞 <a href="tel:${BRAND.phone}" style="color:rgba(255,255,255,0.9);text-decoration:none;">${BRAND.phoneDisplay}</a> | ✉️ <a href="mailto:${BRAND.email}" style="color:rgba(255,255,255,0.9);text-decoration:none;">${BRAND.email}</a></p></div>`;

// ---- ARTICLE SECTIONS ----
const enrichmentBlocks = [
  tipBlock('לפני בחירת רכיב, בדקו את סביבת העבודה: טמפרטורה, לחות, רעשי EMI ודרגת IP הנדרשת. רכיב עם מפרט לא מתאים לסביבה — יכשל גם אם הוא מבריק בנייר.'),
  howtoBlock('כיצד לבחון ספק ציוד תעשייתי — 5 שאלות מנחות', [
    'האם הספק מייצג את המותג רשמית בישראל?',
    'מה זמן התגובה לפנייה טכנית דחופה?',
    'האם יש מלאי זמין בארץ לרכיבים קריטיים?',
    'האם ניתן לקבל תמיכה טכנית בעברית?',
    'מהן תנאי האחריות ומדיניות ההחלפה?'
  ]),
  dynBlock('לפי נתוני תעשייה, כ-40% מתקלות ציוד בקרה נובעות מהתאמה לא נכונה בין הרכיב לסביבת העבודה — לא מכשל של הרכיב עצמו. בדיקה מוקדמת חוסכת זמן וכסף.'),
  howtoBlock('בדיקת תאימות תקשורת — רשימת בדיקה', [
    'האם הפרוטוקול (Modbus TCP / EtherNet/IP / Profinet) תואם לציוד הקיים?',
    'האם כתובות IP ו-Node ID מוגדרים ללא חפיפה?',
    'האם יש תמיכה בזיהוי תקלות תקשורת מרחוק?',
    'האם קיים גיבוי תקשורת לנקודות קריטיות?'
  ]),
  dynBlock('מתג תעשייתי Managed עם VLAN מאפשר הפרדה מאובטחת בין רשת הבקרה (OT) לרשת הניהול (IT), ומפחית משמעותית סיכוני סייבר בתעשייה.'),
  tipBlock('כאשר משווים הצעות מחיר, בקשו לכלול עלות רישיון, תוכנת תכנות, הדרכה ועלות חלפים ל-3 שנים. ההצעה הזולה בשנה הראשונה לעיתים היא היקרה ביותר לטווח ארוך.')
];

let sectionsHtml = '';
let blockIndex = 0;
const insertMidCTAAfter = Math.floor(sections.length / 2);

for (let i = 0; i < sections.length; i++) {
  const s = sections[i];
  const sectionContent = typeof s.content === 'string' ? s.content : '';

  // Sanitize content — fix font and color rules
  const cleanContent = sectionContent
    .replace(/font-family:[^;'"]+Arimo[^;'"]+;?/gi, `font-family:'Heebo',Arial,sans-serif;`)
    .replace(/#354052/g, BRAND.text)
    .replace(/color:#0E6BA8/g, `color:${BRAND.accent}`);

  sectionsHtml += sectionH2(s.id, s.heading);

  // Add section content
  if (cleanContent.includes('<p')) {
    sectionsHtml += cleanContent;
  } else {
    sectionsHtml += bodyPara(cleanContent);
  }

  // Add enrichment block (one per section, cycling)
  if (blockIndex < enrichmentBlocks.length) {
    sectionsHtml += enrichmentBlocks[blockIndex++];
  }

  // Add section image
  if (images[i]) {
    sectionsHtml += sectionImg(images[i], s.heading);
  }

  // Add mid-article CTA after ~40% of sections
  if (i === insertMidCTAAfter) {
    sectionsHtml += midCTA;
  }
}

// ---- PRODUCTS SECTION ----
const products = [
  {name: 'בקרים מתוכנתים (PLC)', desc: 'בקרי PLC תעשייתיים למערכות ייצור ואוטומציה', url: 'https://www.galoz.co.il/627680-%D7%91%D7%A7%D7%A8%D7%99%D7%9D-%D7%9E%D7%AA%D7%95%D7%9B%D7%A0%D7%AA%D7%99%D7%9D-%D7%9E%D7%95%D7%93%D7%95%D7%9C%D7%A8%D7%99%D7%9D/', img: 'https://d3m9l0v76dty0.cloudfront.net/system/photos/969317/original/647c52f91134a3275ab30d687acff6d5.jpg?1741787320'},
  {name: 'בקרי טמפרטורה', desc: 'בקרי טמפרטורה מדויקים לתהליכים תעשייתיים', url: 'https://www.galoz.co.il/627674-%D7%91%D7%A7%D7%A8%D7%99-%D7%98%D7%9E%D7%A4%D7%A8%D7%98%D7%95%D7%A8%D7%94/', img: 'https://d3m9l0v76dty0.cloudfront.net/system/photos/970613/original/b3bd187697754f34c6f49442c17bc7e3.jpg?1742115142'},
  {name: 'מד טמפרטורה ולחות', desc: 'חיישני טמפרטורה ולחות לתעשייה ותהליכים', url: 'https://www.galoz.co.il/627658-%D7%9E%D7%93-%D7%98%D7%9E%D7%A4%D7%A8%D7%98%D7%95%D7%A8%D7%94-%D7%95%D7%9C%D7%97%D7%95%D7%AA/', img: 'https://d3m9l0v76dty0.cloudfront.net/system/photos/969764/original/9041ae4b888923e5cebfad6abcc82664.jpg?1741873812'},
  {name: 'מתמרים תעשייתיים', desc: 'מתמרי אות לסוגי מדידה שונים בתעשייה', url: 'https://www.galoz.co.il/627673-%D7%9E%D7%AA%D7%9E%D7%A8/', img: 'https://d3m9l0v76dty0.cloudfront.net/system/photos/970644/original/3584a4aaa67d22ee12f1245a648c0e64.jpg?1742116917'},
  {name: 'מדי זרימה תעשייתיים', desc: 'מדידת זרימה נוזלים וגזים בדיוק גבוה', url: 'https://www.galoz.co.il/627668-%D7%96%D7%A8%D7%99%D7%9E%D7%94/', img: 'https://d3m9l0v76dty0.cloudfront.net/system/photos/968812/original/b387b2f71f86446944dd7dad0dfb8a5e.jpg?1741684626'},
  {name: 'אנקודרים תעשייתיים', desc: 'קידוד מיקום וסיבובים לצירי מכונות ומנועים', url: 'https://www.galoz.co.il/627671-%D7%90%D7%A0%D7%A7%D7%95%D7%93%D7%A8%D7%99%D7%9D/', img: 'https://d3m9l0v76dty0.cloudfront.net/system/photos/968810/original/1753abf85b9a080caa8a5b7261ae8dcf.jpg?1741684159'}
];

const productCards = products.map(p => `
<div style="background:#ffffff;border:1px solid ${BRAND.border};border-radius:12px;overflow:hidden;position:relative;" onmouseover="this.style.borderColor='${BRAND.primary}';this.style.boxShadow='0 4px 16px rgba(0,86,150,0.15)'" onmouseout="this.style.borderColor='${BRAND.border}';this.style.boxShadow='none'">
<div style="overflow:hidden;height:160px;"><img src="${p.img}" alt="${p.name}" width="300" height="160" style="width:100%;height:160px;object-fit:cover;display:block;" loading="lazy"></div>
<div style="padding:12px;">
<p style="font-size:0.85rem;font-weight:700;color:${BRAND.dark};margin:0 0 4px;">${p.name}</p>
<p style="font-size:0.8rem;color:#64748b;margin:0 0 8px;">${p.desc}</p>
<span style="display:inline-block;font-size:0.75rem;font-weight:700;color:${BRAND.primary};padding:4px 10px;border:1px solid ${BRAND.primary};border-radius:20px;">לפרטים &larr;</span>
</div>
<a href="${p.url}" style="position:absolute;inset:0;" aria-label="${p.name}"></a>
</div>`).join('');

const productsSection = `
